121	// ── Helpers ──────────────────────────────────────────────────
122	
123	/// Read an env file and return the value for `key`, or None if the key is
124	/// absent. The bash regime files use `KEY=value` lines (unquoted); comment
125	/// and blank lines are skipped. The trailing newline is stripped from value.
126	fn rbtdrp_read_env_value(path: &Path, key: &str) -> Option<String> {
127	    let content = std::fs::read_to_string(path).ok()?;
128	    let prefix = format!("{}=", key);
129	    for line in content.lines() {
130	        let trimmed = line.trim_start();
131	        if trimmed.starts_with('#') {
132	            continue;
133	        }
134	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
135	            return Some(rest.to_string());
136	        }
137	    }
138	    None
139	}
140	
141	/// Resolve a path that may be absolute or relative-to-project-root.
142	fn rbtdrp_resolve(root: &Path, raw: &str) -> PathBuf {
143	    if Path::new(raw).is_absolute() {
144	        PathBuf::from(raw)
145	    } else {
146	        root.join(raw)
147	    }
148	}
149	
150	/// Class A — working tree clean (`git status --porcelain` empty).
151	fn rbtdrp_check_tree_clean(root: &Path, violations: &mut Vec<String>) {
152	    match Command::new("git")
153	        .args(["status", "--porcelain"])
154	        .current_dir(root)
155	        .output()
156	    {
157	        Ok(out) if out.status.success() => {
158	            let stdout = String::from_utf8_lossy(&out.stdout);
159	            let trimmed = stdout.trim();
160	            if !trimmed.is_empty() {
161	                violations.push(format!(
162	                    "working tree not clean — uncommitted changes:\n{}",
163	                    trimmed
164	                ));
165	            }
166	        }
167	        Ok(out) => violations.push(format!(
168	            "git status --porcelain failed (exit {}): {}",
169	            out.status.code().unwrap_or(-1),
170	            String::from_utf8_lossy(&out.stderr).trim()
171	        )),
172	        Err(e) => violations.push(format!("git status invocation failed: {}", e)),
173	    }
174	}
175	
176	/// Class B — five site-specific RBRR fields are blank.
177	fn rbtdrp_check_rbrr_fields(rbrr: &Path, violations: &mut Vec<String>) {
178	    for field in RBTDRP_RBRR_BLANK_FIELDS {
179	        if let Some(value) = rbtdrp_read_env_value(rbrr, field) {
180	            if !value.is_empty() {
181	                violations.push(format!(
182	                    "RBRR field non-blank: {}={} (in {})",
183	                    field,
184	                    value,
185	                    rbrr.display()
186	                ));
187	            }
188	        }
189	    }
190	}
191	
192	/// Class C — no RBRA credential files at the four role paths.
193	fn rbtdrp_check_rbra_files(root: &Path, secrets_dir: &str, violations: &mut Vec<String>) {
194	    if secrets_dir.is_empty() {
195	        violations.push(
196	            "RBRR_SECRETS_DIR is blank — cannot resolve credential paths".to_string(),
197	        );
198	        return;
199	    }
200	    let secrets = rbtdrp_resolve(root, secrets_dir);
201	    for role in RBTDRP_RBRA_ROLES {
202	        let path = secrets.join(role).join(RBTDRP_RBRA_FILE);
203	        if path.exists() {
204	            violations.push(format!("RBRA credential present: {}", path.display()));
205	        }
206	    }
207	}
208	
209	/// Class D — every nameplate's RBRN_SENTRY_HALLMARK and RBRN_BOTTLE_HALLMARK
210	/// is blank.
211	fn rbtdrp_check_nameplate_hallmarks(root: &Path, violations: &mut Vec<String>) {
212	    let dot_dir = root.join(RBTDRP_DOT_DIR);
213	    let entries = match std::fs::read_dir(&dot_dir) {
214	        Ok(e) => e,
215	        Err(e) => {
216	            violations.push(format!("cannot read {}: {}", dot_dir.display(), e));
217	            return;
218	        }
219	    };
220	    for entry in entries.flatten() {
221	        let np_dir = entry.path();
222	        if !np_dir.is_dir() {
223	            continue;
224	        }
225	        let rbrn = np_dir.join(RBTDRP_RBRN_FILE);
226	        if !rbrn.exists() {
227	            continue;
228	        }
229	        for field in RBTDRP_RBRN_BLANK_FIELDS {
230	            if let Some(value) = rbtdrp_read_env_value(&rbrn, field) {
231	                if !value.is_empty() {
232	                    violations.push(format!(
233	                        "nameplate hallmark non-blank: {}={} (in {})",
234	                        field,
235	                        value,
236	                        rbrn.display()
237	                    ));
238	                }
239	            }
240	        }
241	    }
242	}
243	
244	/// Class E — every vessel rbrv.env has RBRV_RELIQUARY blank and every
245	/// RBRV_IMAGE_*_ANCHOR field blank.
246	fn rbtdrp_check_vessel_depot_fields(
247	    root: &Path,
248	    vessel_dir: &str,
249	    violations: &mut Vec<String>,
250	) {
251	    if vessel_dir.is_empty() {
252	        violations.push("RBRR_VESSEL_DIR is blank — cannot scan vessels".to_string());
253	        return;
254	    }
255	    let vroot = rbtdrp_resolve(root, vessel_dir);
256	    let entries = match std::fs::read_dir(&vroot) {
257	        Ok(e) => e,
258	        Err(e) => {
259	            violations.push(format!("cannot read {}: {}", vroot.display(), e));
260	            return;
261	        }
262	    };
263	    for entry in entries.flatten() {
264	        let v_dir = entry.path();
265	        if !v_dir.is_dir() {
266	            continue;
267	        }
268	        let rbrv = v_dir.join(RBTDRP_RBRV_FILE);
269	        if !rbrv.exists() {
270	            continue;
271	        }
272	        rbtdrp_scan_rbrv_file(&rbrv, violations);
273	    }
274	}
275	
276	/// Scan a single rbrv.env for non-blank RBRV_RELIQUARY and RBRV_IMAGE_*_ANCHOR
277	/// fields.
278	fn rbtdrp_scan_rbrv_file(rbrv: &Path, violations: &mut Vec<String>) {
279	    let content = match std::fs::read_to_string(rbrv) {
280	        Ok(c) => c,
281	        Err(e) => {
282	            violations.push(format!("cannot read {}: {}", rbrv.display(), e));
283	            return;
284	        }
285	    };
286	    for line in content.lines() {
287	        let trimmed = line.trim_start();
288	        if trimmed.starts_with('#') {
289	            continue;
290	        }
291	        let (key, value) = match trimmed.split_once('=') {
292	            Some(kv) => kv,
293	            None => continue,
294	        };
295	        let is_reliquary = key == "RBRV_RELIQUARY";
296	        let is_anchor = key.starts_with("RBRV_IMAGE_") && key.ends_with("_ANCHOR");
297	        if (is_reliquary || is_anchor) && !value.is_empty() {
298	            violations.push(format!(
299	                "vessel depot-scoped field non-blank: {}={} (in {})",
300	                key,
301	                value,
302	                rbrv.display()
303	            ));
304	        }
305	    }
306	}
307	
308	// ── Env-file rewrite + git commit helpers ────────────────────
309	
310	/// Rewrite each line in `content` whose key matches an entry in `pairs`
311	/// (matched as `KEY=`) to `KEY=value`. Lines whose keys are not in `pairs`
312	/// pass through unchanged. The trailing-newline shape is preserved.
313	fn rbtdrp_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
314	    let mut result: String = content
315	        .lines()
316	        .map(|line| {
317	            for (key, value) in pairs {
318	                let assign = format!("{}=", key);
319	                if line.starts_with(&assign) {
320	                    return format!("{}{}", assign, value);
321	                }
322	            }
323	            line.to_string()
324	        })
325	        .collect::<Vec<_>>()
326	        .join("\n");
327	    if content.ends_with('\n') {
328	        result.push('\n');
329	    }
330	    result
331	}
332	
333	/// `git add <file> && git commit -m <message>` from `root`. Bubbles the
334	/// underlying stderr on either step's failure.
335	fn rbtdrp_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
336	    let add = Command::new("git")
337	        .args(["add", file])
338	        .current_dir(root)
339	        .output()
340	        .map_err(|e| format!("rbtdrp: git add invocation failed: {}", e))?;
341	    if !add.status.success() {
342	        return Err(format!(
343	            "rbtdrp: git add failed (exit {}): {}",
344	            add.status.code().unwrap_or(-1),
345	            String::from_utf8_lossy(&add.stderr).trim()
346	        ));
347	    }
348	
349	    let commit = Command::new("git")
350	        .args(["commit", "-m", message])
351	        .current_dir(root)
352	        .output()
353	        .map_err(|e| format!("rbtdrp: git commit invocation failed: {}", e))?;
354	    if !commit.status.success() {
355	        return Err(format!(
356	            "rbtdrp: git commit failed (exit {}): {}",
357	            commit.status.code().unwrap_or(-1),
358	            String::from_utf8_lossy(&commit.stderr).trim()
359	        ));
360	    }
361	
362	    Ok(())
363	}
364	
365	// ── Throwaway-prefix install ─────────────────────────────────
366	
367	/// Idempotently install throwaway RBRR prefixes into `.rbk/rbrr.env`.
368	///
369	/// Pristine-lifecycle cases that need non-blank prefixes (depot/governor/
370	/// retriever/director lifecycle) call this as their first step. The helper
371	/// reads current values; if `RBRR_CLOUD_PREFIX` and `RBRR_RUNTIME_PREFIX`
372	/// already match the throwaway markers, returns `Ok(())` with no side
373	/// effect. Otherwise rewrites both lines in place, then `git add` +
374	/// `git commit` the change. One commit per fixture run regardless of which
375	/// case is the first to call it.
376	///
377	/// HEAD walks off marshal-zero after the commit; recovery is `rbw-MZ`,
378	/// matching the pristine fixture's start-over-from-zero failure mode.
379	pub(crate) fn rbtdrp_install_throwaway_prefixes(root: &Path) -> Result<(), String> {
380	    let rbrr = root.join(RBTDRP_RBRR_FILE);
381	    let cloud = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX).unwrap_or_default();
382	    let runtime =
383	        rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
384	
385	    if cloud == RBTDRP_THROWAWAY_CLOUD_PREFIX && runtime == RBTDRP_THROWAWAY_RUNTIME_PREFIX {
386	        return Ok(());
387	    }
388	
389	    let content = std::fs::read_to_string(&rbrr)
390	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
391	    let new_content = rbtdrp_replace_env_fields(
392	        &content,
393	        &[
394	            (RBTDRP_FIELD_RBRR_CLOUD_PREFIX, RBTDRP_THROWAWAY_CLOUD_PREFIX),
395	            (
396	                RBTDRP_FIELD_RBRR_RUNTIME_PREFIX,
397	                RBTDRP_THROWAWAY_RUNTIME_PREFIX,
398	            ),
399	        ],
400	    );
401	    std::fs::write(&rbrr, &new_content)
402	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
403	
404	    let commit_msg = format!(
405	        "pristine-lifecycle fixture: install throwaway RBRR prefixes ({}/{})",
406	        RBTDRP_THROWAWAY_CLOUD_PREFIX, RBTDRP_THROWAWAY_RUNTIME_PREFIX
407	    );
408	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
409	}
