411	/// Pick the next free moniker for `family_stem` by walking the depot_list
412	/// invocation's BURV output dir for `<family>NNNNNN.depot` files, parsing
413	/// the numeric suffix from each, and returning `<family><max + 1>`. Returns
414	/// `<family>RBTDRP_FAMILY_NUMERIC_FLOOR` when no matching files exist or the
415	/// output dir is missing (first run, no prior depots).
416	fn rbtdrp_pick_next_moniker(
417	    list_result: &crate::rbtdri_invocation::rbtdri_InvokeResult,
418	    family_stem: &str,
419	) -> Result<String, String> {
420	    let dir = list_result
421	        .burv_output
422	        .join(crate::rbtdri_invocation::RBTDRI_BURV_OUTPUT_SUBDIR);
423	
424	    let entries = match std::fs::read_dir(&dir) {
425	        Ok(e) => e,
426	        Err(_) => {
427	            return Ok(format!("{}{}", family_stem, RBTDRP_FAMILY_NUMERIC_FLOOR));
428	        }
429	    };
430	
431	    let suffix_ext = format!(".{}", RBTDRP_FACT_EXT_DEPOT);
432	    let mut max_suffix: Option<u32> = None;
433	    for entry in entries.flatten() {
434	        let name = match entry.file_name().into_string() {
435	            Ok(n) => n,
436	            Err(_) => continue,
437	        };
438	        let stem = match name.strip_suffix(&suffix_ext) {
439	            Some(s) => s,
440	            None => continue,
441	        };
442	        let numeric = match stem.strip_prefix(family_stem) {
443	            Some(s) => s,
444	            None => continue,
445	        };
446	        if numeric.len() != RBTDRP_FAMILY_NUMERIC_WIDTH {
447	            continue;
448	        }
449	        let parsed: u32 = match numeric.parse() {
450	            Ok(n) => n,
451	            Err(_) => continue,
452	        };
453	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
454	    }
455	
456	    let next = match max_suffix {
457	        Some(m) => m + 1,
458	        None => RBTDRP_FAMILY_NUMERIC_FLOOR,
459	    };
460	    Ok(format!("{}{}", family_stem, next))
461	}
462	
463	/// Compose the depot project_id from kindled regime values. Mirrors RBDC's
464	/// derivation: `${RBRR_CLOUD_PREFIX}d-${moniker}`. Used by cases 2 and 3 to
465	/// recover the project_id post-levy without re-reading a fact file (the
466	/// pre-collapse `rbgp_fact_depot_project_id` producer is gone).
467	fn rbtdrp_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
468	    let rbrr = root.join(RBTDRP_RBRR_FILE);
469	    let cloud_prefix = rbtdrp_read_env_value(&rbrr, RBTDRP_FIELD_RBRR_CLOUD_PREFIX)
470	        .ok_or_else(|| format!("RBRR_CLOUD_PREFIX missing from {}", rbrr.display()))?;
471	    Ok(format!("{}d-{}", cloud_prefix, moniker))
472	}
473	
474	/// Set `RBRR_DEPOT_MONIKER` in rbrr.env to `moniker` and commit. Cases 2-3
475	/// use this to install a moniker that drives `RBDC_DEPOT_PROJECT_ID` via
476	/// kindle derivation. The commit is separate from the throwaway-prefix
477	/// commit so the audit trail shows the moniker landing as its own pace.
478	fn rbtdrp_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
479	    let rbrr = root.join(RBTDRP_RBRR_FILE);
480	    let content = std::fs::read_to_string(&rbrr)
481	        .map_err(|e| format!("rbtdrp: read {}: {}", rbrr.display(), e))?;
482	    let new_content = rbtdrp_replace_env_fields(
483	        &content,
484	        &[(RBTDRP_FIELD_RBRR_DEPOT_MONIKER, moniker)],
485	    );
486	    std::fs::write(&rbrr, &new_content)
487	        .map_err(|e| format!("rbtdrp: write {}: {}", rbrr.display(), e))?;
488	
489	    let commit_msg = format!(
490	        "pristine-lifecycle fixture: set {}={}",
491	        RBTDRP_FIELD_RBRR_DEPOT_MONIKER, moniker
492	    );
493	    rbtdrp_git_add_and_commit(root, RBTDRP_RBRR_FILE, &commit_msg)
494	}
