496	// ── Case ─────────────────────────────────────────────────────
497	
498	/// Case 1 — marshal-zero attestation. Aggregates all five violation classes
499	/// into a single diagnostic. A passing run is the proof that `rbw-MZ` was
500	/// just executed and committed.
501	fn rbtdrp_marshal_zero_attestation(_dir: &Path) -> rbtdre_Verdict {
502	    let root = match std::env::current_dir() {
503	        Ok(r) => r,
504	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot resolve project root: {}", e)),
505	    };
506	
507	    let rbrr = root.join(RBTDRP_RBRR_FILE);
508	    if !rbrr.exists() {
509	        return rbtdre_Verdict::Fail(format!("RBRR file not found: {}", rbrr.display()));
510	    }
511	
512	    let secrets_dir = rbtdrp_read_env_value(&rbrr, "RBRR_SECRETS_DIR").unwrap_or_default();
513	    let vessel_dir = rbtdrp_read_env_value(&rbrr, "RBRR_VESSEL_DIR").unwrap_or_default();
514	
515	    let mut violations: Vec<String> = Vec::new();
516	
517	    rbtdrp_check_tree_clean(&root, &mut violations);
518	    rbtdrp_check_rbrr_fields(&rbrr, &mut violations);
519	    rbtdrp_check_rbra_files(&root, &secrets_dir, &mut violations);
520	    rbtdrp_check_nameplate_hallmarks(&root, &mut violations);
521	    rbtdrp_check_vessel_depot_fields(&root, &vessel_dir, &mut violations);
522	
523	    if violations.is_empty() {
524	        return rbtdre_Verdict::Pass;
525	    }
526	
527	    let body = violations
528	        .iter()
529	        .map(|v| format!("  - {}", v))
530	        .collect::<Vec<_>>()
531	        .join("\n");
532	    rbtdre_Verdict::Fail(format!(
533	        "marshal-zero attestation failed — {} violation(s):\n{}\n\n\
534	         remedy: tt/rbw-MZ.MarshalZeroes.sh, then commit and rerun.",
535	        violations.len(),
536	        body
537	    ))
538	}
