542	/// Wrapper invocation: call `rbtdri_invoke_global` and tee stdout/stderr to
543	/// `dir/<label>-stdout.txt` / `dir/<label>-stderr.txt` for diagnostic review.
544	/// Returns `Ok(InvokeResult)` regardless of exit code; callers decide what
545	/// counts as failure.
546	fn rbtdrp_invoke_logged(
547	    ctx: &mut rbtdri_Context,
548	    colophon: &str,
549	    args: &[&str],
550	    extra_env: &[(&str, &str)],
551	    dir: &Path,
552	    label: &str,
553	) -> Result<crate::rbtdri_invocation::rbtdri_InvokeResult, String> {
554	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
555	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
556	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
557	    Ok(result)
558	}
