1032	    let depot_fact_path = list_after
1033	        .burv_output
1034	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
1035	        .join(format!("{}.{}", moniker, RBTDRP_FACT_EXT_DEPOT));
1036	
1037	    if !depot_fact_path.exists() {
1038	        return rbtdre_Verdict::Pass;
1039	    }
1040	
1041	    let depot_state = match std::fs::read_to_string(&depot_fact_path) {
1042	        Ok(s) => s.trim().to_string(),
1043	        Err(e) => {
1044	            return rbtdre_Verdict::Fail(format!(
1045	                "read depot fact '{}': {}",
1046	                depot_fact_path.display(),
1047	                e
1048	            ))
1049	        }
1050	    };
1051	
1052	    if depot_state == RBTDRP_DELETE_REQUESTED {
1053	        return rbtdre_Verdict::Pass;
1054	    }
1055	
1056	    rbtdre_Verdict::Fail(format!(
1057	        "depot '{}' (project '{}') still present with unexpected state '{}' after unmake \
1058	         (expected absent or '{}')",
1059	        moniker, project_id, depot_state, RBTDRP_DELETE_REQUESTED
1060	    ))
1061	}
1062	
1063	// ── Section registry ─────────────────────────────────────────
1064	
1065	pub static RBTDRP_SECTIONS_PRISTINE_LIFECYCLE: &[rbtdre_Section] = &[
1066	    rbtdre_Section {
1067	        name: "pristine-lifecycle-gate",
1068	        cases: &[case!(rbtdrp_marshal_zero_attestation)],
1069	    },
1070	    rbtdre_Section {
1071	        name: "pristine-lifecycle-arc",
1072	        cases: &[
1073	            case!(rbtdrp_depot_stand_up),
1074	            case!(rbtdrp_sa_cycle),
1075	            case!(rbtdrp_depot_tear_down),
1076	        ],
1077	    },
1078	];
1079	
1080	pub static RBTDRP_FIXTURE_PRISTINE_LIFECYCLE: rbtdre_Fixture = rbtdre_Fixture {
1081	    name: RBTDRM_FIXTURE_PRISTINE_LIFECYCLE,
1082	    disposition: rbtdre_Disposition::StateProgressing,
1083	    setup: None,
1084	    teardown: None,
1085	    sections: RBTDRP_SECTIONS_PRISTINE_LIFECYCLE,
1086	};
