150	/// Per-fixture required colophons. Returns None for unknown fixtures.
151	pub fn rbtdrm_required_colophons(fixture: &str) -> Option<&'static [&'static str]> {
152	    match fixture {
153	        RBTDRM_FIXTURE_TADMOR
154	        | RBTDRM_FIXTURE_MORIAH
155	        | RBTDRM_FIXTURE_SRJCL
156	        | RBTDRM_FIXTURE_PLUML => Some(&[
157	            RBTDRM_COLOPHON_CHARGE,
158	            RBTDRM_COLOPHON_QUENCH,
159	            RBTDRM_COLOPHON_WRIT,
160	            RBTDRM_COLOPHON_FIAT,
161	            RBTDRM_COLOPHON_BARK,
162	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
163	        ]),
164	        RBTDRM_FIXTURE_HALLMARK_LIFECYCLE => Some(&[
165	            RBTDRM_COLOPHON_ORDAIN,
166	            RBTDRM_COLOPHON_ABJURE,
167	            RBTDRM_COLOPHON_REKON_HALLMARK,
168	            RBTDRM_COLOPHON_AUDIT_HALLMARKS,
169	        ]),
170	        RBTDRM_FIXTURE_BATCH_VOUCH => Some(&[
171	            RBTDRM_COLOPHON_ORDAIN,
172	            RBTDRM_COLOPHON_ABJURE,
173	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
174	            RBTDRM_COLOPHON_VOUCH,
175	            RBTDRM_COLOPHON_TALLY,
176	        ]),
177	        RBTDRM_FIXTURE_ACCESS_PROBE => Some(&[RBTDRM_COLOPHON_ACCESS_PROBE]),
178	        RBTDRM_FIXTURE_ENROLLMENT_VALIDATION
179	        | RBTDRM_FIXTURE_REGIME_VALIDATION
180	        | RBTDRM_FIXTURE_REGIME_SMOKE
181	        | RBTDRM_FIXTURE_CALIBRANT_VERDICTS
182	        | RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST
183	        | RBTDRM_FIXTURE_CALIBRANT_PROGRESSING
184	        | RBTDRM_FIXTURE_CALIBRANT_SENTINEL => Some(&[]),
185	        RBTDRM_FIXTURE_PRISTINE_LIFECYCLE => Some(&[
186	            RBTDRM_COLOPHON_DEPOT_LEVY,
187	            RBTDRM_COLOPHON_DEPOT_LIST,
188	            RBTDRM_COLOPHON_DEPOT_UNMAKE,
189	            RBTDRM_COLOPHON_GOV_MANTLE,
190	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
191	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
192	            RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER,
193	            RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR,
194	            RBTDRM_COLOPHON_ACCESS_PROBE,
195	        ]),
196	        RBTDRM_FIXTURE_CANONICAL_ESTABLISH => Some(&[
197	            RBTDRM_COLOPHON_DEPOT_LEVY,
198	            RBTDRM_COLOPHON_DEPOT_LIST,
199	            RBTDRM_COLOPHON_GOV_MANTLE,
200	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
201	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
202	            RBTDRM_COLOPHON_ACCESS_PROBE,
203	        ]),
204	        RBTDRM_FIXTURE_ONBOARDING_SEQUENCE => Some(&[
205	            RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
206	            RBTDRM_COLOPHON_YOKE_RELIQUARY,
207	            RBTDRM_COLOPHON_ENSHRINE_VESSEL,
208	            RBTDRM_COLOPHON_ORDAIN,
209	            RBTDRM_COLOPHON_KLUDGE_SENTRY,
210	            RBTDRM_COLOPHON_KLUDGE_BOTTLE,
211	            RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE,
212	            RBTDRM_COLOPHON_SUMMON,
213	            RBTDRM_COLOPHON_PLUMB_FULL,
214	            RBTDRM_COLOPHON_PLUMB_COMPACT,
215	            RBTDRM_COLOPHON_REKON_HALLMARK,
216	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
217	            RBTDRM_COLOPHON_ABJURE,
218	        ]),
219	        RBTDRM_FIXTURE_HANDBOOK_RENDER => Some(&[
220	            RBTDRM_COLOPHON_ONBOARD_START_HERE,
221	            RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE,
222	            RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER,
223	            RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR,
224	            RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE,
225	            RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD,
226	            RBTDRM_COLOPHON_ONBOARD_PAYOR_HB,
227	            RBTDRM_COLOPHON_ONBOARD_GOVERNOR_HB,
228	            RBTDRM_COLOPHON_HANDBOOK_TOP,
229	            RBTDRM_COLOPHON_HANDBOOK_WINDOWS,
230	            RBTDRM_COLOPHON_HW_DOCKER_DESKTOP,
231	            RBTDRM_COLOPHON_HW_DOCKER_CONTEXT,
232	            RBTDRM_COLOPHON_PAYOR_ESTABLISH,
233	            RBTDRM_COLOPHON_PAYOR_REFRESH,
234	            RBTDRM_COLOPHON_QUOTA_BUILD,
235	        ]),
236	        _ => None,
237	    }
238	}
239	
240	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
241	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
242	    let required = match rbtdrm_required_colophons(fixture) {
243	        Some(r) => r,
244	        None => {
245	            return Err(format!(
246	                "rbtd: unknown fixture '{}' — not registered in manifest",
247	                fixture
248	            ));
249	        }
250	    };
251	    for colophon in required {
252	        let found = manifest.split_whitespace().any(|token| token == *colophon);
253	        if !found {
254	            return Err(format!(
255	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
256	                colophon, fixture
257	            ));
258	        }
259	    }
260	    Ok(())
261	}
