14	//
15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTDRI — tabtarget invocation layer for theurge
18	//
19	// Theurge invokes bottle operations exclusively through tabtargets, never
20	// reimplementing bash command logic. This module provides:
21	//
22	//   1. Tabtarget discovery — imprint-scoped, global, or nameplate-scoped
23	//   2. Tabtarget execution with BURV isolation — per-invocation output/temp dirs
24	//   3. Ifrit verdict parsing — extract verdict from ifrit stdout + exit code
25	//   4. BURV fact file reading — extract structured output from tabtarget results
26	
27	use std::path::{Path, PathBuf};
28	use std::process::Command;
29	
30	use crate::rbtdre_engine::rbtdre_Verdict;
31	use crate::rbtdrm_manifest::RBTDRM_COLOPHON_BARK;
32	
33	/// Ifrit binary name inside the bottle container.
34	const RBTDRI_IFRIT_BINARY: &str = "rbid";
35	
36	/// BUK dispatch output subdirectory — tabtargets write facts to BURV_OUTPUT_ROOT_DIR/current.
37	/// Matches BURD_OUTPUT_DIR = "${BURC_OUTPUT_ROOT_DIR}/current" from bud_dispatch.sh.
38	pub const RBTDRI_BURV_OUTPUT_SUBDIR: &str = "current";
39	
40	/// Env var name read by `buc_require` (buc_command.sh:335) to bypass interactive
41	/// confirmation prompts in non-interactive contexts (test fixtures, automation).
42	pub const RBTDRI_BURE_CONFIRM_KEY: &str = "BURE_CONFIRM";
43	
44	/// Value paired with `RBTDRI_BURE_CONFIRM_KEY` to skip the confirmation prompt.
45	pub const RBTDRI_BURE_CONFIRM_SKIP: &str = "skip";
46	
47	// ── Invocation result ────────────────────────────────────────
48	
49	/// Captured output from a tabtarget invocation.
50	#[derive(Debug)]
51	pub struct rbtdri_InvokeResult {
52	    pub stdout: String,
53	    pub stderr: String,
54	    pub exit_code: i32,
55	    pub burv_output: PathBuf,
56	}
57	
58	// ── Invocation context ───────────────────────────────────────
59	
60	/// Per-case invocation context. Tracks BURV isolation state so each tabtarget
61	/// invocation within a case gets its own output and temp directories, matching
62	/// the zbuto_invoke() pattern from buto_operations.sh.
63	///
64	/// `fixture` carries the fixture name. For crucible fixtures (tadmor/srjcl/
65	/// pluml) the fixture name happens to equal a valid nameplate moniker — that's
66	/// the convention crucible-scoped tabtargets exploit when imprinting (e.g.,
67	/// `rbw-cC.Charge.{fixture}.sh`). Non-crucible fixtures (regime-*, calibrant-*,
68	/// canonical-*, etc.) carry their fixture name in this slot too, but no
69	/// nameplate-shaped consumer reads them.
70	pub struct rbtdri_Context {
71	    pub(crate) project_root: PathBuf,
72	    pub(crate) fixture: String,
73	    pub(crate) burv_root: PathBuf,
74	    pub(crate) invoke_count: u32,
75	}
76	
77	impl rbtdri_Context {
78	    pub fn new(project_root: &Path, fixture: &str, burv_root: &Path) -> Self {
79	        Self {
80	            project_root: project_root.to_path_buf(),
81	            fixture: fixture.to_string(),
82	            burv_root: burv_root.to_path_buf(),
83	            invoke_count: 0,
84	        }
85	    }
86	
87	    pub fn fixture(&self) -> &str {
88	        &self.fixture
89	    }
90	
91	    pub fn project_root(&self) -> &Path {
92	        &self.project_root
93	    }
94	}
95	
96	// ── Tabtarget discovery ──────────────────────────────────────
97	
98	/// Find the tabtarget script for a colophon + imprint (nameplate or role).
99	///
100	/// Scans tt/ for files matching `{colophon}.*.{imprint}.sh`.
101	/// Returns error if zero or multiple matches — exactly one must exist.
102	pub fn rbtdri_find_tabtarget(
103	    project_root: &Path,
104	    colophon: &str,
105	    imprint: &str,
106	) -> Result<PathBuf, String> {
107	    let tt_dir = project_root.join("tt");
108	    let prefix = format!("{}.", colophon);
109	    let suffix = format!(".{}.sh", imprint);
110	
111	    let entries = std::fs::read_dir(&tt_dir)
112	        .map_err(|e| format!("rbtdri: cannot read tt/ directory: {}", e))?;
113	
114	    let matches: Vec<PathBuf> = entries
115	        .filter_map(|entry| entry.ok())
116	        .map(|entry| entry.path())
117	        .filter(|path| {
118	            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
119	                name.starts_with(&prefix) && name.ends_with(&suffix)
120	            } else {
121	                false
122	            }
123	        })
124	        .collect();
125	
126	    match matches.len() {
127	        0 => Err(format!(
128	            "rbtdri: no tabtarget for colophon '{}' imprint '{}'",
129	            colophon, imprint
130	        )),
131	        1 => Ok(matches.into_iter().next().unwrap()),
132	        n => Err(format!(
133	            "rbtdri: {} tabtargets match colophon '{}' imprint '{}' — expected exactly one",
134	            n, colophon, imprint
135	        )),
136	    }
137	}
138	
139	/// Find a global tabtarget (no imprint suffix).
140	///
141	/// Scans tt/ for files matching `{colophon}.{frontispiece}.sh` (exactly two dots).
142	/// Rejects files with imprint suffixes (three+ dots).
143	pub fn rbtdri_find_tabtarget_global(
144	    project_root: &Path,
145	    colophon: &str,
146	) -> Result<PathBuf, String> {
147	    let tt_dir = project_root.join("tt");
148	    let prefix = format!("{}.", colophon);
149	
150	    let entries = std::fs::read_dir(&tt_dir)
151	        .map_err(|e| format!("rbtdri: cannot read tt/ directory: {}", e))?;
152	
153	    let matches: Vec<PathBuf> = entries
154	        .filter_map(|entry| entry.ok())
155	        .map(|entry| entry.path())
156	        .filter(|path| {
157	            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
158	                if name.starts_with(&prefix) && name.ends_with(".sh") {
159	                    // Global: no imprint — exactly one part between colophon and .sh
160	                    let middle = &name[prefix.len()..name.len() - 3]; // strip ".sh"
161	                    !middle.contains('.')
162	                } else {
163	                    false
164	                }
165	            } else {
166	                false
167	            }
168	        })
169	        .collect();
170	
171	    match matches.len() {
172	        0 => Err(format!(
173	            "rbtdri: no global tabtarget for colophon '{}'",
174	            colophon
175	        )),
176	        1 => Ok(matches.into_iter().next().unwrap()),
177	        n => Err(format!(
178	            "rbtdri: {} global tabtargets match colophon '{}' — expected exactly one",
179	            n, colophon
180	        )),
181	    }
182	}
183	
184	// ── Tabtarget invocation with BURV isolation ─────────────────
185	
186	/// Internal: execute a resolved tabtarget with BURV isolation and optional extra env vars.
187	fn rbtdri_invoke_impl(
188	    ctx: &mut rbtdri_Context,
189	    tabtarget: &Path,
190	    args: &[&str],
191	    extra_env: &[(&str, &str)],
192	) -> Result<rbtdri_InvokeResult, String> {
193	    let invoke_num = ctx.invoke_count;
194	    ctx.invoke_count += 1;
195	
196	    let invoke_dir = ctx.burv_root.join(format!("invoke-{:05}", invoke_num));
197	    let burv_output = invoke_dir.join("output");
198	    let burv_temp = invoke_dir.join("temp");
199	
200	    std::fs::create_dir_all(&burv_output)
201	        .map_err(|e| format!("rbtdri: failed to create BURV output dir: {}", e))?;
202	    std::fs::create_dir_all(&burv_temp)
203	        .map_err(|e| format!("rbtdri: failed to create BURV temp dir: {}", e))?;
204	
205	    let mut cmd = Command::new(tabtarget);
206	    cmd.args(args)
207	        .current_dir(&ctx.project_root)
208	        .env("BURV_OUTPUT_ROOT_DIR", &burv_output)
209	        .env("BURV_TEMP_ROOT_DIR", &burv_temp);
210	
211	    for (key, value) in extra_env {
212	        cmd.env(key, value);
213	    }
214	
215	    let output = cmd
216	        .output()
217	        .map_err(|e| format!("rbtdri: failed to execute '{}': {}", tabtarget.display(), e))?;
218	
219	    Ok(rbtdri_InvokeResult {
220	        stdout: String::from_utf8_lossy(&output.stdout).into_owned(),
221	        stderr: String::from_utf8_lossy(&output.stderr).into_owned(),
222	        exit_code: output.status.code().unwrap_or(-1),
223	        burv_output,
224	    })
225	}
226	
227	/// Invoke a fixture-imprinted tabtarget (colophon + ctx.fixture). For crucible
228	/// fixtures the fixture name is also a nameplate moniker, which is the
229	/// imprint shape this resolves against.
230	pub fn rbtdri_invoke(
231	    ctx: &mut rbtdri_Context,
232	    colophon: &str,
233	    args: &[&str],
234	) -> Result<rbtdri_InvokeResult, String> {
235	    let tabtarget = rbtdri_find_tabtarget(&ctx.project_root, colophon, &ctx.fixture)?;
236	    rbtdri_invoke_impl(ctx, &tabtarget, args, &[])
237	}
238	
239	/// Invoke a global tabtarget (no imprint) with optional extra environment variables.
240	pub fn rbtdri_invoke_global(
241	    ctx: &mut rbtdri_Context,
242	    colophon: &str,
243	    args: &[&str],
244	    extra_env: &[(&str, &str)],
245	) -> Result<rbtdri_InvokeResult, String> {
246	    let tabtarget = rbtdri_find_tabtarget_global(&ctx.project_root, colophon)?;
247	    rbtdri_invoke_impl(ctx, &tabtarget, args, extra_env)
248	}
249	
250	/// Invoke a tabtarget with an explicit imprint (overrides ctx.fixture for discovery).
251	pub fn rbtdri_invoke_imprint(
252	    ctx: &mut rbtdri_Context,
253	    colophon: &str,
254	    imprint: &str,
255	    args: &[&str],
256	) -> Result<rbtdri_InvokeResult, String> {
257	    let tabtarget = rbtdri_find_tabtarget(&ctx.project_root, colophon, imprint)?;
258	    rbtdri_invoke_impl(ctx, &tabtarget, args, &[])
259	}
260	
261	// ── BURV fact file reading ───────────────────────────────────
262	
263	/// Read a fact file from a tabtarget's BURV output directory.
264	/// Fact files are single-line values written by tabtargets to BURD_OUTPUT_DIR,
265	/// which is BURV_OUTPUT_ROOT_DIR/current per BUK dispatch convention.
266	pub fn rbtdri_read_burv_fact(
267	    result: &rbtdri_InvokeResult,
268	    fact_name: &str,
269	) -> Result<String, String> {
270	    let path = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR).join(fact_name);
271	    let content = std::fs::read_to_string(&path)
272	        .map_err(|e| format!("rbtdri: cannot read fact '{}' from {}: {}", fact_name, path.display(), e))?;
273	    let trimmed = content.trim().to_string();
274	    if trimmed.is_empty() {
275	        return Err(format!("rbtdri: fact '{}' is empty in {}", fact_name, path.display()));
276	    }
277	    Ok(trimmed)
278	}
279	
280	/// Enumerate multi-fact files in a tabtarget's BURV output directory.
281	/// Multi-facts follow the convention `<root>.<ext>` written by buf_write_fact_multi;
282	/// returns the sorted list of roots whose files have the requested extension.
283	/// Returns an empty Vec if no matching files exist.
284	pub fn rbtdri_read_burv_facts_multi(
285	    result: &rbtdri_InvokeResult,
286	    extension: &str,
287	) -> Result<Vec<String>, String> {
288	    let dir = result.burv_output.join(RBTDRI_BURV_OUTPUT_SUBDIR);
289	    let entries = std::fs::read_dir(&dir).map_err(|e| {
290	        format!(
291	            "rbtdri: cannot enumerate fact dir {}: {}",
292	            dir.display(),
293	            e
294	        )
295	    })?;
296	    let suffix = format!(".{}", extension);
297	    let mut roots: Vec<String> = entries
298	        .filter_map(|entry| entry.ok())
299	        .filter_map(|entry| entry.file_name().into_string().ok())
300	        .filter_map(|name| name.strip_suffix(&suffix).map(str::to_string))
301	        .collect();
302	    roots.sort();
303	    Ok(roots)
304	}
305	
306	// ── Ifrit verdict parsing ────────────────────────────────────
307	
308	/// Ifrit verdict wire protocol: ifrit prints exactly one line matching
309	/// `IFRIT_VERDICT: PASS` or `IFRIT_VERDICT: FAIL <detail>` to stdout.
310	/// Missing verdict line is always a failure — no silent pass-through.
311	pub fn rbtdri_parse_ifrit_verdict(stdout: &str, exit_code: i32) -> rbtdre_Verdict {
312	    for line in stdout.lines() {
313	        let trimmed = line.trim();
314	        if let Some(rest) = trimmed.strip_prefix("IFRIT_VERDICT:") {
315	            let rest = rest.trim();
316	            if rest.starts_with("PASS") {
317	                return rbtdre_Verdict::Pass;
318	            }
319	            if let Some(detail) = rest.strip_prefix("FAIL") {
320	                let detail = detail.trim();
321	                if detail.is_empty() {
322	                    return rbtdre_Verdict::Fail("ifrit reported failure".to_string());
323	                }
324	                return rbtdre_Verdict::Fail(detail.to_string());
325	            }
326	        }
327	    }
328	
329	    if exit_code == 0 {
330	        rbtdre_Verdict::Fail("ifrit exited 0 but no verdict line found".to_string())
331	    } else {
332	        rbtdre_Verdict::Fail(format!("ifrit exited {} with no verdict line", exit_code))
333	    }
334	}
335	
336	/// Invoke the ifrit binary inside a charged bottle via the bark tabtarget.
337	/// The attack selector argument tells ifrit which attack module to run.
338	/// Returns a test verdict based on ifrit's stdout verdict line and exit code.
339	pub fn rbtdri_invoke_ifrit(
340	    ctx: &mut rbtdri_Context,
341	    attack_selector: &str,
342	) -> Result<rbtdre_Verdict, String> {
343	    let result = rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &[RBTDRI_IFRIT_BINARY, attack_selector])?;
344	    Ok(rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code))
345	}
