273	/// Run a fixture: setup hook → cases → teardown hook (finally-shaped).
274	///
275	/// Expects the invocation context to already be installed in the thread-local
276	/// (via `rbtdrc_set_context`); setup/teardown access ctx via that channel.
277	///
278	/// Setup failure short-circuits cases but still invokes teardown. Teardown
279	/// errors are surfaced as warnings via stderr; the function never panics on
280	/// teardown failure.
281	pub fn rbtdre_run_fixture(
282	    fixture: &'static rbtdre_Fixture,
283	    colors: &rbtdre_Colors,
284	    root_temp: &Path,
285	) -> Result<rbtdre_RunResult, String> {
286	    let setup_result = match fixture.setup {
287	        Some(f) => f(),
288	        None => Ok(()),
289	    };
290	
291	    let run_result = match setup_result {
292	        Ok(()) => {
293	            let fail_fast = rbtdre_resolve_fail_fast(fixture.disposition, false)
294	                .expect("disposition-default mode never fails policy resolution");
295	            rbtdre_run_sections(fixture.sections, colors, fail_fast, root_temp)
296	        }
297	        Err(msg) => Err(format!("rbtd: fixture '{}' setup failed: {}", fixture.name, msg)),
298	    };
299	
300	    if let Some(f) = fixture.teardown {
301	        f();
302	    }
303	
304	    run_result
305	}
306	
307	/// Run a single case without charge/quench lifecycle.
308	pub fn rbtdre_run_single_case(
309	    case: &rbtdre_Case,
310	    colors: &rbtdre_Colors,
311	    root_temp: &Path,
312	) -> Result<rbtdre_RunResult, String> {
