18	//
19	// Exercises every handbook display tabtarget and reports per-case pass/fail.
20	// Each case invokes a handbook colophon with no arguments and asserts exit 0.
21	//
22	// Scope note: `rbw-HWdw` (RBZ_HW_DOCKER_WSL_NATIVE) uses the param1 channel
23	// and is deferred to ₢A-AAS (handbook-render-param1-coverage) in ₣A- — the
24	// fixture's uniform "invoke and check exit 0" pattern cannot supply the
25	// required WSL-target argument.
26	
27	use std::path::Path;
28	use std::process::Command;
29	
30	use crate::case;
31	use crate::rbtdre_engine::{rbtdre_Disposition, rbtdre_Fixture, rbtdre_Section, rbtdre_Verdict};
32	use crate::rbtdri_invocation::rbtdri_find_tabtarget_global;
33	use crate::rbtdrm_manifest::{
34	    RBTDRM_COLOPHON_HANDBOOK_TOP, RBTDRM_COLOPHON_HANDBOOK_WINDOWS,
35	    RBTDRM_COLOPHON_HW_DOCKER_CONTEXT, RBTDRM_COLOPHON_HW_DOCKER_DESKTOP,
36	    RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE, RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR,
37	    RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER, RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD,
38	    RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE, RBTDRM_COLOPHON_ONBOARD_GOVERNOR_HB,
39	    RBTDRM_COLOPHON_ONBOARD_PAYOR_HB, RBTDRM_COLOPHON_ONBOARD_START_HERE,
40	    RBTDRM_COLOPHON_PAYOR_ESTABLISH, RBTDRM_COLOPHON_PAYOR_REFRESH,
41	    RBTDRM_COLOPHON_QUOTA_BUILD, RBTDRM_FIXTURE_HANDBOOK_RENDER,
42	};
43	
44	// ── Helper ───────────────────────────────────────────────────
45	
46	/// Invoke a handbook tabtarget with no arguments and return Pass iff exit 0.
47	/// Writes stdout/stderr traces to the per-case directory for diagnostic review.
48	fn rbtdrf_hb_render(dir: &Path, colophon: &str, label: &str) -> rbtdre_Verdict {
49	    let root = match std::env::current_dir() {
50	        Ok(r) => r,
51	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
52	    };
53	
54	    let tt = match rbtdri_find_tabtarget_global(&root, colophon) {
